@startuml
package "com" {
    package "Iluwatar" {
        package "prototype" {
            interface Prototype {
                + Prototype()
                + clone() : Object
            }
            interface Beast {
                + Beast()
                + clone() : Beast
            }
            interface Warlord {
                + Warlord()
                + clone() : Warlord
            }
            interface Mage {
                + Mage()
                + clone() : Mage
            }
            class ElfBeast {
